+    fn doctor_reconstruct_rejects_missing_storage_root() {
+        let result = handle_doctor_reconstruct_with(
+            Some(Path::new("/tmp/nonexistent.db")),
+            Some(Path::new("/nonexistent/storage/root")),
+            false,
+            false,
